import{c as t,Q as s,j as o,m as a}from"./chunks/framework.BPKcPtvA.js";const h=JSON.parse('{"title":"How do I suspend a customer?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/suspend-customer.md","filePath":"guide/recipes/admin/suspend-customer.md","lastUpdated":1779094756000}'),r={name:"guide/recipes/admin/suspend-customer.md"};function n(i,e,l,u,c,d){return s(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="how-do-i-suspend-a-customer" tabindex="-1">How do I suspend a customer? <a class="header-anchor" href="#how-do-i-suspend-a-customer" aria-label="Permalink to &quot;How do I suspend a customer?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong>, <strong>Infra Ops</strong>, or <strong>Account Manager</strong> (within scope)</p></div><p>Suspension blocks portal access for everyone in a customer without losing their data — useful for non-payment, contract disputes, or anything you might reverse.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Customers</strong> and click the customer.</li><li>Click <strong>Suspend Customer</strong> in the actions menu (top right).</li><li>Enter a <strong>reason</strong> (visible to other operators on this customer&#39;s detail page).</li><li>Confirm.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><ul><li>All users belonging to the customer are signed out and blocked at sign-in.</li><li>The customer record shows status <strong>Suspended</strong> with the reason and the operator who applied it.</li><li>Tenants, instances, and data are untouched. Billing continues to accrue unless you also stop usage at the instance level.</li></ul><p>To bring them back, use <strong>Reactivate</strong> on the customer detail page.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./churn-customer">How do I churn a customer?</a></li></ul>',10)])])}const m=t(r,[["render",n]]);export{h as __pageData,m as default};
